'use client';

import { useState } from 'react';
import { useRouter } from 'next/navigation';
import { Mail, Lock, Eye, EyeOff, ArrowRight, User } from 'lucide-react';
import toast from 'react-hot-toast';
import { useAuth } from '@/components/providers/AuthProvider';
import { cn } from '@/lib/utils';

const LOGO_SRC = "data:image/jpeg;base64,";
const BG_SRC = "data:image/jpeg;base64,";

export default function AuthPage() {
    const [modo, setModo] = useState<'login' | 'registro'>('login');
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [nombre, setNombre] = useState('');
    const [mostrarPassword, setMostrarPassword] = useState(false);
    const [cargando, setCargando] = useState(false);
    const { loginEmail, loginGoogle, registro } = useAuth();
    const router = useRouter();

    const handleEmail = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!email || !password) { toast.error('Completa todos los campos'); return; }
        if (modo === 'registro' && !nombre) { toast.error('Ingresa tu nombre'); return; }
        setCargando(true);
        try {
            if (modo === 'login') {
                await loginEmail(email, password);
                toast.success('\u00a1Bienvenido!');
            } else {
                await registro(email, password, nombre);
                toast.success('\u00a1Cuenta creada!');
            }
            router.push('/dashboard');
        } catch (error: unknown) {
            const err = error as { code?: string };
            const m: Record<string, string> = {
                'auth/user-not-found': 'Usuario no encontrado',
                'auth/wrong-password': 'Contrase\u00f1a incorrecta',
                'auth/invalid-credential': 'Credenciales incorrectas',
                'auth/email-already-in-use': 'El correo ya est\u00e1 registrado',
                'auth/weak-password': 'M\u00ednimo 6 caracteres',
                'auth/invalid-email': 'Correo inv\u00e1lido',
            };
            toast.error(m[err.code || ''] || 'Error de autenticaci\u00f3n');
        } finally { setCargando(false); }
    };

    const handleGoogle = async () => {
        setCargando(true);
        try {
            await loginGoogle();
            toast.success('\u00a1Bienvenido!');
            router.push('/dashboard');
        } catch { toast.error('Error con Google'); }
        finally { setCargando(false); }
    };

    return (
        <div className="min-h-screen flex relative overflow-hidden bg-gray-950">
            <style>{`
                @keyframes shimmer {
                    0%   { background-position: -200% center; }
                    100% { background-position: 200% center; }
                }
                .atempo-glow {
                    background: linear-gradient(90deg,
                        #fff 0%, #fff 25%,
                        #c4b5fd 38%, #fff 50%,
                        #93c5fd 62%, #fff 75%, #fff 100%
                    );
                    background-size: 200% auto;
                    -webkit-background-clip: text;
                    background-clip: text;
                    -webkit-text-fill-color: transparent;
                    animation: shimmer 3.5s linear infinite;
                    filter: drop-shadow(0 0 18px rgba(196,181,253,0.55));
                }
            `}</style>

            {/* Fondo imagen sutil */}
            <div className="absolute inset-0 z-0" style={{
                backgroundImage: `url(${BG_SRC})`,
                backgroundSize: 'cover', backgroundPosition: 'center',
                opacity: 0.18, filter: 'blur(1px)',
            }} />
            <div className="absolute inset-0 z-0 bg-gradient-to-br from-gray-950/90 via-gray-900/80 to-gray-950/90" />

            {/* Panel izquierdo desktop */}
            <div className="hidden lg:flex lg:w-1/2 relative z-10 flex-col items-center justify-center p-12 text-white">
                <div className="max-w-md text-center">
                    <div className="w-24 h-24 rounded-2xl mx-auto mb-8 shadow-2xl overflow-hidden border border-white/10">
                        <img src={LOGO_SRC} alt="Atempo" className="w-full h-full object-cover" />
                    </div>
                    <h1 className="text-5xl font-bold mb-3 tracking-widest">
                        <span className="atempo-glow">ATEMPO</span>
                    </h1>
                    <p className="text-base text-white/50 mb-10">Sistema Financiero de Atempo Art Studios</p>
                    <div className="space-y-3 text-left mb-8">
                        {[
                            { emoji: '💱', label: 'Tasas BCV y paralelo en tiempo real' },
                            { emoji: '🏪', label: 'Punto de Venta con pago m\u00f3vil' },
                            { emoji: '📊', label: 'Dashboard de inteligencia comercial' },
                            { emoji: '📒', label: 'Contabilidad y P&G en Bs y USD' },
                            { emoji: '🔒', label: 'Seguro con Firebase Authentication' },
                        ].map((f) => (
                            <div key={f.label} className="flex items-center gap-3 bg-white/5 rounded-xl px-4 py-3 border border-white/[0.08]">
                                <span className="text-xl">{f.emoji}</span>
                                <span className="text-sm text-white/60">{f.label}</span>
                            </div>
                        ))}
                    </div>
                    <p className="text-xs text-white/30">
                        Tasas actualizadas: BCV &middot; Monitor D\u00f3lar &middot; CoinGecko
                    </p>
                </div>
            </div>

            {/* Panel derecho formulario */}
            <div className="w-full lg:w-1/2 flex items-center justify-center p-6 relative z-10">
                <div className="w-full max-w-md">

                    {/* Logo mobile */}
                    <div className="lg:hidden text-center mb-8">
                        <div className="w-16 h-16 rounded-2xl mx-auto mb-3 overflow-hidden border border-white/10 shadow-xl">
                            <img src={LOGO_SRC} alt="Atempo" className="w-full h-full object-cover" />
                        </div>
                        <h1 className="text-2xl font-bold tracking-widest">
                            <span className="atempo-glow">ATEMPO</span>
                        </h1>
                        <p className="text-xs text-white/40 mt-1">Sistema Financiero de Atempo Art Studios</p>
                    </div>

                    <div className="bg-white/5 backdrop-blur-xl border border-white/10 rounded-2xl p-8 shadow-2xl">
                        {/* Tabs */}
                        <div className="flex bg-white/5 rounded-xl p-1 mb-6 border border-white/10">
                            {(['login', 'registro'] as const).map((m) => (
                                <button key={m}
                                    className={cn('flex-1 py-2 rounded-lg text-sm font-medium transition-all',
                                        modo === m ? 'bg-white/15 text-white' : 'text-white/40 hover:text-white/70'
                                    )}
                                    onClick={() => setModo(m)}
                                >
                                    {m === 'login' ? 'Iniciar Sesi\u00f3n' : 'Registrarse'}
                                </button>
                            ))}
                        </div>

                        <form onSubmit={handleEmail} className="space-y-4">
                            {modo === 'registro' && (
                                <div>
                                    <label className="text-xs text-white/40 mb-1 block">Nombre completo</label>
                                    <div className="relative">
                                        <User className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-white/30" />
                                        <input type="text" placeholder="Tu nombre completo" value={nombre}
                                            onChange={(e) => setNombre(e.target.value)}
                                            className="w-full pl-10 pr-4 py-3 bg-white/5 border border-white/10 rounded-xl text-white placeholder-white/20 focus:outline-none focus:border-white/30 text-sm" />
                                    </div>
                                </div>
                            )}
                            <div>
                                <label className="text-xs text-white/40 mb-1 block">Correo electr\u00f3nico</label>
                                <div className="relative">
                                    <Mail className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-white/30" />
                                    <input type="email" placeholder="correo@email.com" value={email}
                                        onChange={(e) => setEmail(e.target.value)} autoComplete="email"
                                        className="w-full pl-10 pr-4 py-3 bg-white/5 border border-white/10 rounded-xl text-white placeholder-white/20 focus:outline-none focus:border-white/30 text-sm" />
                                </div>
                            </div>
                            <div>
                                <label className="text-xs text-white/40 mb-1 block">Contrase\u00f1a</label>
                                <div className="relative">
                                    <Lock className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-white/30" />
                                    <input type={mostrarPassword ? 'text' : 'password'}
                                        placeholder={modo === 'registro' ? 'M\u00ednimo 6 caracteres' : '\u2022\u2022\u2022\u2022\u2022\u2022\u2022\u2022'}
                                        value={password} onChange={(e) => setPassword(e.target.value)}
                                        autoComplete={modo === 'login' ? 'current-password' : 'new-password'}
                                        className="w-full pl-10 pr-10 py-3 bg-white/5 border border-white/10 rounded-xl text-white placeholder-white/20 focus:outline-none focus:border-white/30 text-sm" />
                                    <button type="button" onClick={() => setMostrarPassword(!mostrarPassword)}
                                        className="absolute right-3 top-1/2 -translate-y-1/2 text-white/30 hover:text-white/60">
                                        {mostrarPassword ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
                                    </button>
                                </div>
                            </div>
                            <button type="submit" disabled={cargando}
                                className={cn('w-full py-3 bg-white text-gray-900 font-semibold rounded-xl hover:bg-white/90 transition-all flex items-center justify-center gap-2 text-sm',
                                    cargando && 'opacity-70 cursor-not-allowed')}>
                                {cargando
                                    ? <div className="w-4 h-4 border-2 border-gray-400 border-t-gray-900 rounded-full animate-spin" />
                                    : <>{modo === 'login' ? 'Iniciar Sesi\u00f3n' : 'Crear Cuenta'}<ArrowRight className="w-4 h-4" /></>
                                }
                            </button>
                        </form>

                        <div className="flex items-center gap-3 my-4">
                            <div className="flex-1 h-px bg-white/10" />
                            <span className="text-xs text-white/30">o contin\u00faa con</span>
                            <div className="flex-1 h-px bg-white/10" />
                        </div>

                        <button onClick={handleGoogle} disabled={cargando}
                            className="w-full py-3 bg-white/5 border border-white/10 rounded-xl text-white hover:bg-white/10 transition-all flex items-center justify-center gap-3 text-sm disabled:opacity-50">
                            <svg className="w-4 h-4" viewBox="0 0 24 24">
                                <path fill="#4285F4" d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z"/>
                                <path fill="#34A853" d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z"/>
                                <path fill="#FBBC05" d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z"/>
                                <path fill="#EA4335" d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z"/>
                            </svg>
                            Continuar con Google
                        </button>

                        <p className="text-xs text-center text-white/30 mt-5">
                            {modo === 'login' ? (
                                <>\u00bfA\u00fan no tienes cuenta?{' '}
                                    <button onClick={() => setModo('registro')} className="text-white/60 hover:text-white underline">Reg\u00edstrate</button>
                                </>
                            ) : (
                                <>\u00bfYa tienes cuenta?{' '}
                                    <button onClick={() => setModo('login')} className="text-white/60 hover:text-white underline">Inicia sesi\u00f3n</button>
                                </>
                            )}
                        </p>
                    </div>

                    <p className="text-xs text-center text-white/25 mt-4">
                        Al ingresar, aceptas los T\u00e9rminos y Condiciones de ATEMPO
                    </p>
                    <p className="text-xs text-center text-white/20 mt-1">
                        Tasas actualizadas: BCV \u00b7 Monitor D\u00f3lar \u00b7 CoinGecko
                    </p>
                </div>
            </div>
        </div>
    );
}
